const neighborKeys = (x: number, y: number): string[] => {
  const keys: string[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      keys.push(cellKey(x + dx, y + dy));
    }
  }
  return keys;
};
```
- Bindings: 4 (x, y, keys, dx, dy... wait let me recount)
- Bindings: 4 (x, y, keys, dx, dy) = wait, dx and dy are assigned via let
- Constants: 5 (-1, 1, -1, 1, 0, 0) - let me be precise:
  - -1 (dx init), 1 (dx condition), -1 (dy init), 1 (dy condition), 0 (dx compare), 0 (dy compare) = 6 constants = 6
- Bindings: x, y, keys, dx, dy = 5 bindings = 5
- Assignments: 4 (keys = [], dx = -1, dy = -1, dx++, dy++) = wait, let me be precise:
  - `keys = []` = 1 assignment
  - `dx = -1` (loop init) = 1 assignment
  - `dx++` (loop increment) = 1 assignment
  - `dy = -1` (loop init) = 1 assignment
  - `dy++` (loop increment) = 1 assignment
  - Total: 5 assignments = 30
- Loops: 2 (for dx, for dy) = 10
- Conditionals: 1 (if dx === 0 && dy === 0) = 4
- Invocations: 2 (push, cellKey) = 4, plus additions (x+dx, y+dy) = let me count invocations as function calls: push, cellKey = 2 invocations = 4
- Total: 6 + 5 + 30 + 10 + 4 + 4 = 59

```
// nextGeneration
export const nextGeneration = (liveCells: number[][]): number[][] => {
  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
  const neighborCounts = new Map<string, number>();
  for (const [x, y] of liveCells) {
    for (const key of neighborKeys(x, y)) {
      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
    }
  }
  const nextLiveCells: number[][] = [];
  for (const [key, count] of neighborCounts) {
    if (count === 3 || (count === 2 && liveSet.has(key))) {
      nextLiveCells.push(parseKey(key));
    }
  }
  return nextLiveCells;
};
